s:ui-execute-js.script:
if(!window.$restService) {
	throw new Error('$restService not exposed on window');
}
window.$restService.setTrackApiCalls(true);
window.$restService.clearTrackedApiCalls();
return true;

if(!window.$restService) {
	throw new Error('$restService not exposed on window');
}
var calls = window.$restService.getTrackedApiCalls() || [];
var uriFilter = '${(param.uri)!""}';
if(uriFilter) {
	calls = calls.filter(function(c) {
		return (c.url || '').indexOf(uriFilter) >= 0;
	});
}
return calls;

if(!window.$restService) {
	throw new Error('$restService not exposed on window');
}
window.$restService.clearTrackedApiCalls();
return true;
